INSERT INTO `sys_oper_log` VALUES (2820, '员工转正申请主-修改', 2, 'com.ruoyi.web.controller.staffservice.ApplyFormalController.applyFormalEdit()', 'POST', 1, 'admin', '软件开发部门', '/project-flow/staff-service/apply-formal/apply-formal-edit', '127.0.0.1', '内网IP', '{\"id\":[\"14\"],\"workDate\":[\"2025-08-04\"],\"serviceDate\":[\"2025-08-13\"],\"servicePost\":[\"完成\"],\"workSummary\":[\"的v操作<style>\\r\\n        .btn-download-line{\\r\\n            display:inline-flex;\\r\\n            align-items:center;\\r\\n            gap:10px;\\r\\n            padding:10px 24px;\\r\\n            font-size:15px;\\r\\n            color:#0066ff;\\r\\n            border:2px solid #0066ff;\\r\\n            border-radius:25px;\\r\\n            background:transparent;\\r\\n            cursor:pointer;\\r\\n            text-decoration:none;\\r\\n            position:relative;\\r\\n            overflow:hidden;\\r\\n            transition:color .3s ease;\\r\\n        }\\r\\n        .btn-download-line::before{\\r\\n            content:\'\';\\r\\n            position:absolute;\\r\\n            left:0;\\r\\n            top:0;\\r\\n            height:100%;\\r\\n            width:0;\\r\\n            background:#0066ff;\\r\\n            z-index:-1;\\r\\n            transition:width .3s ease;\\r\\n        }\\r\\n        .btn-download-line:hover{\\r\\n            color:#fff;\\r\\n        }\\r\\n        .btn-download-line:hover::before{\\r\\n            width:100%;\\r\\n        }\\r\\n    </style>  帮我把这个按钮的大小缩减至原来的三分之二\\r\\n复制\\r\\n下面给出 3 种常用做法，任选其一即可把按钮整体缩小到原来的 2/3（≈66.7%）。\\r\\n核心思路：\\r\\n所有与尺寸有关的值（字体、内边距、圆角、行高、图标大小等）都乘 2/3。\\r\\n如果按钮内部还有其它绝对尺寸（如伪元素里的背景图尺寸、SVG 宽高、阴影等），也要同步乘 2/3。\\r\\n如果你只想一次性整体缩放，不想改样式表，可以用第 3 种“CSS 统一缩放”方案。\\r\\n✅ 方案 1：直接改样式值（最干净）\\r\\ncss\\r\\n复制\\r\\n.btn-download-line {\\r\\n    /* 原来 15px → 15 × 2/3 = 10px */\\r\\n    font-size: 10px;\\r\\n\\r\\n    /* 原来 10px 24px → 7px 16px（四舍五入） */\\r\\n    padding: 7px 16px;\\r\\n\\r\\n    /* 原来 25px → 17px */\\r\\n    border-radius: 17px;\\r\\n\\r\\n    /* 其它与尺寸相关的值同理 */\\r\\n    gap: 7px;                 /* 10px → 7px */\\r\\n}\\r\\n\\r\\n/* 如果按钮里还有图标，也要同步缩小 */\\r\\n.btn-download-line svg,\\r\\n.btn-download-line img {\\r\\n    width:  13px;  /* 假设原来是 20px → 20×2/3≈13px */\\r\\n    height: 13px;\\r\\n}\\r\\n✅ 方案 2：用 rem 全局比例（推荐可维护）\\r\\n先把根字号设成 10px（方便算），再把按钮所有尺寸换成 rem，最后用一行 html { font-size: 6.67px; } 全局缩到 2/3：\\r\\ncss\\r\\n复制\\r\\nhtml {\\r\\n    /*', '{\"msg\":\"操作成功\",\"code\":0}', 0, NULL, '2025-08-08 14:45:48', 62);
